#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <limits.h>

typedef long long ll;
typedef unsigned int uint;

#define si(x) scanf("%d", &x)
#define sl(x) scanf("%ld", &x)
#define sll(x) scanf("%lld", &x)
#define sc(x) scanf("%c", &x)
#define ss(x) scanf("%s", x)
#define f(i, a, b) for(i = a; i < b; i++)

int main() {
  char a[101], b[101];

  ss(a);
  ss(b);

  int l1 = 0, l2 = 0;
  int countA[26] = {0}, countB[26] = {0}, i;
  for(i = 0; a[i]; i++) {
    countA[a[i] - 'a']++;
    l1++;
  }

  for(i = 0; b[i]; i++) {
    countB[b[i] - 'a']++;
    l2++;
  }

  if(l2 > l1) {
    printf("need tree\n");
    return 0;
  }

  int flagA = 0, flagB = 0;
  f(i, 0, 26) {
    if(countA[i] > countB[i]) {
      countA[i] = countA[i] - countB[i];
      countB[i] = 0;
    } else {
      countB[i] = countB[i] - countA[i];
      countA[i] = 0;
    }

    if(countA[i] > 0)
      flagA = 1;

    if(countB[i] > 0)
      flagB = 1;
  }

  if(!flagA && !flagB)
    printf("array\n");
  else if(flagB)
    printf("need tree\n");
  else {
    int j = 0;

      f(i, 0, l2) {
        while(j < l1 && b[i] != a[j])
          j++;

        if(j == l1)
          break;
        else
          j++;
      }

      if(i == l2)
        printf("automaton\n");
      else
        printf("both\n");
  }
  return 0;
}

